import ast, os

# 检查 src/main.py re-export 完整性
main_exports = set()
with open('src/main.py') as f:
    tree = ast.parse(f.read())
for node in ast.walk(tree):
    if isinstance(node, ast.ImportFrom):
        for alias in node.names:
            name = alias.asname or alias.name
            main_exports.add(name)

# 扫描各模块的公开名字
missing = {}
src_dir = 'src'
for fname in os.listdir(src_dir):
    if not fname.endswith('.py') or fname.startswith('_'):
        continue
    if fname == 'main.py':
        continue
    with open(os.path.join(src_dir, fname)) as f:
        tree = ast.parse(f.read())
    module_exports = set()
    for node in ast.iter_child_nodes(tree):
        if isinstance(node, (ast.FunctionDef, ast.AsyncFunctionDef)):
            if not node.name.startswith('_'):
                module_exports.add(node.name)
        elif isinstance(node, ast.ClassDef):
            if not node.name.startswith('_'):
                module_exports.add(node.name)
        elif isinstance(node, ast.Assign):
            for target in node.targets:
                if isinstance(target, ast.Name) and not target.id.startswith('_') and target.id.isupper():
                    module_exports.add(target.id)
    not_exported = module_exports - main_exports
    if not_exported:
        missing[fname] = not_exported

if missing:
    print('缺失 re-export:')
    for f, names in sorted(missing.items()):
        print(f'  {f}: {sorted(names)}')
else:
    print('所有公开符号均已 re-export ✅')
